const body = items[0].json || {};
const headers = (body.headers && typeof body.headers === 'object') ? body.headers : (body.raw_headers && typeof body.raw_headers === 'object' ? body.raw_headers : {});
const authHeader = headers.authorization || headers.Authorization || '';
const expected = 'Bearer ' + String($env.DITI_WEBHOOK_SECRET || $env.WEBHOOK_SECRET || '');

// Minimal auth guard (in addition to Webhook header auth)
if (!expected.trim() || String(authHeader || '').trim() !== expected.trim()) {
  return [{ json: { __is_error: true, ok: false, error: 'unauthorized', message: 'Unauthorized.' } }];
}

const title = typeof body.title === 'string' ? body.title.trim() : '';
if (!title) {
  return [{ json: { __is_error: true, ok: false, error: 'missing_title', message: 'Kein Titel angegeben.' } }];
}

const params = (body.params && typeof body.params === 'object') ? body.params : {};
const source = (body.source && typeof body.source === 'object') ? body.source : {};
return [{ json: {
  __is_error: false,
  intent: body.intent || 'task.create',
  title,
  params: {
    due: typeof params.due === 'string' ? params.due : '',
    prio: typeof params.prio === 'string' && params.prio ? params.prio : 'M',
    project: typeof params.project === 'string' ? params.project : '',
    context: typeof params.context === 'string' ? params.context : ''
  },
  source: {
    channel: String(source.channel || 'telegram'),
    chat_id: String(source.chat_id || ''),
    message_id: String(source.message_id || ''),
    timestamp: String(source.timestamp || new Date().toISOString())
  }
} }];

function generateULID() {
  const encoding = '0123456789ABCDEFGHJKMNPQRSTVWXYZ';
  let now = Date.now();
  let timePart = '';
  for (let index = 9; index >= 0; index -= 1) {
    timePart = encoding[now % 32] + timePart;
    now = Math.floor(now / 32);
  }
  let randomPart = '';
  for (let index = 0; index < 16; index += 1) {
    randomPart += encoding[Math.floor(Math.random() * 32)];
  }
  return timePart + randomPart;
}

const input = items[0].json || {};
const source = input.source || {};
const dedupKey = String(source.channel || '') + ':' + String(source.message_id || '');

const staticData = getWorkflowStaticData('global');
if (!staticData.seen) staticData.seen = [];
const seen = Array.isArray(staticData.seen) ? staticData.seen : [];

if (dedupKey && seen.includes(dedupKey)) {
  return [{ json: { __is_error: true, ok: false, error: 'duplicate', message: 'Duplicate request.' } }];
}

if (dedupKey) {
  seen.push(dedupKey);
  // cap at 1000 entries
  if (seen.length > 1000) seen.splice(0, seen.length - 1000);
  staticData.seen = seen;
}

const event_id = generateULID();
const event_envelope = {
  event_id,
  event_type: 'task.create',
  source_system: String(source.channel || 'telegram'),
  source_id: String(source.message_id || ''),
  timestamp: String(source.timestamp || new Date().toISOString()),
  actor: 'user',
  payload: {
    intent: 'task.create',
    title: String(input.title || ''),
    params: input.params || {}
  }
};

return [{ json: { ...input, __is_error: false, event_id, event_envelope } }];

const taskResult = items[0].json || {};
const upstream = $('Dedup & Envelope').first().json || {};

// When continueOnFail=true, n8n includes an error object on item.json in many nodes.
if (!taskResult || !taskResult.id) {
  const message = (taskResult && taskResult.error && taskResult.error.message) ? String(taskResult.error.message) : 'Google Tasks error';
  return [{ json: { __is_error: true, ok: false, error: 'google_api_error', message } }];
}

return [{ json: {
  __is_error: false,
  ok: true,
  action: 'task.created',
  task: {
    id: String(taskResult.id),
    title: String(upstream.title || ''),
    due: String((upstream.params && upstream.params.due) || ''),
    list: 'NEXT'
  },
  event_id: String(upstream.event_id || '')
} }];
